// src/components/bloks/Hero.tsx
import { storyblokEditable } from '@storyblok/react/rsc';

export default function Hero({ blok }: { blok: any }) {
    return (
        <section {...storyblokEditable(blok)} className="relative h-screen flex items-center justify-center">
            {blok.background_video && (
                <video
                    autoPlay
                    loop
                    muted
                    playsInline
                    className="absolute max-w-none min-w-full min-h-full w-auto h-auto top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 object-cover z-0"
                >
                    <source src={blok.background_video} type="video/mp4" />
                </video>
            )}
            <div className="z-10 text-center text-white bg-black/50 p-8 rounded-xl max-w-4xl mx-auto">
                <h1 className="text-5xl font-bold mb-4">{blok.headline}</h1>
                <p className="text-xl mb-6">{blok.subheadline}</p>
            </div>
        </section>
    );
}
